async function newChatMessage(widget, chatId, parentIdOrPayload, model, role, message, options = {}) {
    let parentId = parentIdOrPayload;
    let { realModel = null, temperature = 0, stream = true, refMsgId, insert } = options || {};
    let meta = null;
    let type = null;
    let visibility = null;
    let content = null;

    if (typeof parentIdOrPayload === 'object') {
        parentId = parentIdOrPayload.parentId;
        model = parentIdOrPayload.model;
        role = parentIdOrPayload.role;
        message = parentIdOrPayload.message;
        content = parentIdOrPayload.content;
        realModel = parentIdOrPayload.realModel;
        temperature = parentIdOrPayload.temperature || 0;
        stream = parentIdOrPayload.stream == null ? true : parentIdOrPayload.stream;
        refMsgId = parentIdOrPayload.refMsgId;
        insert = parentIdOrPayload.insert;
        meta = parentIdOrPayload.meta || parentIdOrPayload.metadata;
        type = parentIdOrPayload.type;
        visibility = parentIdOrPayload.visibility;
    }

    if (parentId == null) throw new Error('No parent id defined');
    if (!model) throw new Error('No model defined');
    if (!role) throw new Error('No role defined');
    if (message === undefined && content === undefined) throw new Error('No message content defined');

    const body = {
        action: "new-chat-message",
        "chat-id": chatId,
        "parent-id": parentId,
        temperature,
        role,
        model,
        "real-model": realModel,
        message: message !== undefined ? message : content,
        stream,
        "reference-message-id": refMsgId,
        insert,
        meta,
        type,
        visibility
    };

    const response = await fetch(widget.dataURL, {
        method: "POST",
        body: JSON.stringify(body),
        headers: {
            "Content-Type": "application/json"
        }
    });

    if ( !response.ok )
        throw new Error("FIXME: Implement");

    return await response.json();
}

async function updateChatMessage(widget, id, payloadOrOldMessage, newMessage) {
    let oldMessage = payloadOrOldMessage;
    let newVisibility = null;
    let newType = null;
    let newMeta = null;
    let newParentId = null;

    if (payloadOrOldMessage && typeof payloadOrOldMessage === 'object') {
        oldMessage = payloadOrOldMessage.oldMessage;
        newMessage = payloadOrOldMessage.newMessage;
        newVisibility = payloadOrOldMessage.newVisibility;
        newType = payloadOrOldMessage.newType;
        newMeta = payloadOrOldMessage.newMeta;
        newParentId = payloadOrOldMessage.newParentId;
    }

    const body = {
        action: "update-chat-message",
        id,
        "old-message": oldMessage,
        "new-message": newMessage,
        "new-type": newType || undefined,
        "new-visibility": newVisibility || undefined,
        "new-meta": newMeta || undefined,
        "new-parent-id": typeof newParentId === 'number' && newParentId >= 0 ? newParentId : undefined
    };

    const response = await fetch(widget.dataURL, {
        method: "PUT",
        body: JSON.stringify(body),
        headers: {
            "Content-Type": "application/json"
        }
    });

    if ( !response.ok ) {
        console.log("FIXME: Implement");
        return;
    }

    return await response.json();
}
